  <script type="module">
    function filterArray(arr) {
      if (!Array.isArray(arr)) return [];
      return arr.filter(item => typeof item === 'string' && !item.startsWith('$'));
    }
    function safeGet(obj, path, defaultVal) {
      const val = _.get(obj, path);
      if (val === undefined || val === null) return defaultVal;
      return Array.isArray(val) ? (val.length > 0 ? val[0] : defaultVal) : val;
    }

    function populateAllData() {
      const all_vars = getAllVariables();
      // Đã cập nhật đường dẫn biến theo bản dịch YAML tiếng Việt
      const sys_stat = (path, dv) => safeGet(all_vars, `stat_data.Hệ_thống.${path}`, dv);
      const lr_stat = (path, dv) => safeGet(all_vars, `stat_data.Lâm_Nhược_Ngữ.${path}`, dv);
      const lr_stat_obj = (path) => _.get(all_vars, `stat_data.Lâm_Nhược_Ngữ.${path}`, {});
      const lr_stat_arr = (path) => filterArray(lr_stat(path, []));

      // --- Điền dữ liệu Trang 1 ---
      $('#p1-date-time').text(`Ngày ${sys_stat('Ngày', 1)} | ${sys_stat('Thời_gian', '00:00')}`);
      $('#p1-location').text(sys_stat('Địa_điểm', 'Chưa rõ'));
      $('#p1-love-val').text(lr_stat('Độ_hảo_cảm', 0));
      $('#p1-san-val').text(lr_stat('Giá_trị_lý_trí', 100) + '%');
      $('#p1-depth-val').text(lr_stat('Độ_sâu_thôi_miên', 0) + '%');
      $('#p1-status-val').text(lr_stat('Trạng_thái_hiện_tại', 'Bình thường'));
      const clothing_html = lr_stat_arr('Trang_phục_thường_ngày').map(item => `<div class="clothing-item">${item}</div>`).join('');
      $('#p1-clothing-list').html(clothing_html || 'Không');

      // --- Điền dữ liệu Trang 2 ---
      $('#p2-fatigue-val').text(lr_stat('Dữ_liệu_cơ_thể.Độ_mệt_mỏi', 0) + '%');
      $('#p2-pleasure-val').text(lr_stat('Dữ_liệu_cơ_thể.Giá_trị_khoái_cảm', 0) + '%');
      $('#p2-sensitivity-val').text(lr_stat('Dữ_liệu_cơ_thể.Tổng_độ_nhạy_cảm', 0) + '%');
      $('#p2-orgasm-val').text(lr_stat('Dữ_liệu_cơ_thể.Số_lần_lên_đỉnh', 0));

      const p2_parts_container = $('#p2-parts-list');
      p2_parts_container.empty();
      const p2_parts_data = lr_stat_obj('Chi_tiết_bộ_phận_cơ_thể');
      // Các khóa này phải khớp với YAML tiếng Việt
      ['Khoang_miệng', 'Ngực', 'Tiểu_huyệt', 'Âm_vật', 'Hậu_huyệt', 'Ngón_chân'].forEach(key => {
        const data = p2_parts_data[key];
        if (data) {
          const occupied = safeGet(data, 'Đang_bị_chiếm_dụng', 'Không');
          const desc = safeGet(data, 'Mô_tả', '...');
          const status = safeGet(data, 'Trạng_thái', 'Bình thường');

          p2_parts_container.append(`
            <div class="part-item">
              <div class="part-header">
                <span class="part-name">${key.replace(/_/g, ' ')}</span>
                <span class="part-status">${status}</span>
              </div>
              <div class="part-desc">${desc}</div>
              <div class="part-stats">
                <div><span class="part-label">Chiếm dụng: </span><span class="part-value ${occupied !== 'Không' ? 'occupied' : ''}">${occupied}</span></div>
              </div>
            </div>`);
        }
      });

      const p2_equip_container = $('#p2-equipment-list');
      p2_equip_container.empty();
      const p2_equip_data = lr_stat_obj('Trang_bị_đặc_biệt');
      let p2_has_equip = false;
      Object.entries(p2_equip_data).forEach(([key, val]) => {
        if (key.startsWith('$')) return;
        const item = safeGet(val, 0, 'Không');
        if (item !== 'Không') {
          p2_has_equip = true;
          p2_equip_container.append(`<div class="equipment-item">${item}</div>`);
        }
      });
      if (!p2_has_equip) p2_equip_container.html('<div style="opacity: 0.5; font-style: italic;">Không</div>');

      // --- Điền dữ liệu Trang 3 ---
      const getLatest = (path, limit) => lr_stat_arr(path).reverse().slice(0, limit);

      // Mỏ neo nhận thức: 5 cái gần nhất
      $('#p3-anchor-list').html(getLatest('Mỏ_neo_nhận_thức', 5).map(i => `<li>${i}</li>`).join('') || '<li>Không</li>');
      // Ghi chép thôi miên: 3 cái gần nhất
      $('#p3-record-list').html(getLatest('Ghi_chép_thôi_miên', 3).map(i => `<li>${i}</li>`).join('') || '<li>Không</li>');
      // Nhật ký phản hồi: 3 cái gần nhất
      $('#p3-feedback-list').html(getLatest('Nhật_ký_phản_hồi_thôi_miên', 3).map(i => `<li>“${i}”</li>`).join('') || '<li>Không</li>');
    }

    async function init() {
      await waitGlobalInitialized('Mvu');
      populateAllData();
      eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, populateAllData);

      // Logic lật trang
      $('.page-btn').on('click', function() {
        const targetId = $(this).data('target');
        $('.page-btn').removeClass('active');
        $(`.page-btn[data-target="${targetId}"]`).addClass('active');
        $('.page-content').removeClass('active');
        $('#' + targetId).addClass('active');
      });

      // Chức năng gấp gọn
      $('#page-three .memory-title').on('click', function() {
        $(this).toggleClass('active');
        $(this).next('.memory-list').slideToggle('fast');
      });
    }
    $(errorCatched(init));
  </script>
